```javascript
function soma(a, b) {
  if (typeof a === 'number' && typeof b === 'number') { // Verificar se são números
    return a + b;
  } else {
    throw new Error('Operadores precisam ser dois números ou duas strings');
  }
}

console.log(soma(5, 3)); // Exibe o resultado da soma

// Outra opção:
try {
  console.log(soma("soma", "2")); // Verifique se a identificação é válida
} catch (e) {
  console.error(e.message);
}
```
